<script setup lang="ts">
import{reactive,ref,watch}from'vue';import{useAdminInsightsStore}from'../stores/adminInsights';
const store=useAdminInsightsStore();const tab=ref<'feedback'|'rewards'|'commissions'|'reports'>('feedback');const rewardOpen=ref(false);const groups=reactive<Record<string,{addon_code:string;is_active:boolean}>>({});const validity=ref<number|null>(null)
watch(tab,()=>loadTab(),{immediate:true});function loadTab():void{if(tab.value==='feedback')store.loadFeedback();else if(tab.value==='rewards')store.loadPromotions();else if(tab.value==='commissions')store.loadCommissions();else store.loadReport()}
function openRewardSettings():void{for(const preset of store.promotionPresets)groups[preset.key]={addon_code:preset.addon_code??store.promotionAddons[0]?.code??'',is_active:preset.is_active};validity.value=store.promotionValidity;rewardOpen.value=true}
async function saveRewards():Promise<void>{if(await store.savePromotionSettings({promotion_voucher_validity_days:validity.value,groups}))rewardOpen.value=false}
async function pay(id:number):Promise<void>{if(confirm('Record this commission as paid today?'))await store.payCommission(id,new Date().toISOString().slice(0,10))}
</script>
<template><section class="page"><header><p class="eyebrow">DECISION SUPPORT</p><h1>Insights & rewards</h1><p>Review experience, customer rewards, therapist liabilities, and management reports.</p></header><nav class="switch" aria-label="Insight areas"><button v-for="item in ['feedback','rewards','commissions','reports']" :key="item" :class="{active:tab===item}" @click="tab=item as typeof tab">{{item}}</button></nav><p v-if="store.notice" class="notice">{{store.notice}}</p><p v-if="store.error" class="alert">{{store.error}}</p>
<section v-if="tab==='feedback'"><div class="metrics three"><article><strong>{{store.feedbackSummary.positive}}</strong><span>Positive</span></article><article><strong>{{store.feedbackSummary.neutral}}</strong><span>Neutral</span></article><article><strong>{{store.feedbackSummary.negative}}</strong><span>Negative</span></article></div><form class="filters" @submit.prevent="store.loadFeedback(1)"><input v-model="store.feedbackSearch" placeholder="Search feedback" aria-label="Search feedback"><select v-model="store.feedbackSentiment" aria-label="Sentiment"><option value="">All sentiments</option><option value="positive">Positive</option><option value="neutral">Neutral</option><option value="negative">Negative</option></select><button>Apply</button></form><div class="list"><article v-for="item in store.feedback" :key="item.id"><div class="top"><strong>{{item.customer?.name??'Guest'}}</strong><span>{{item.sentiment}}</span></div><p>{{'★'.repeat(item.rating)}} · {{item.service?.name}}</p><blockquote>{{item.comment||'No written comment.'}}</blockquote></article></div></section>
<section v-else-if="tab==='rewards'"><div class="metrics"><article><strong>{{store.promotionSummary.available}}</strong><span>Available</span></article><article><strong>{{store.promotionSummary.reserved}}</strong><span>Reserved</span></article><article><strong>{{store.promotionSummary.used}}</strong><span>Used</span></article><article><strong>{{store.promotionSummary.expired}}</strong><span>Expired</span></article></div><button class="primary" @click="openRewardSettings">Reward settings</button><form class="filters" @submit.prevent="store.loadPromotions(1)"><input v-model="store.promotionSearch" placeholder="Search rewards" aria-label="Search rewards"><select v-model="store.promotionLifecycle" aria-label="Reward status"><option value="">All states</option><option v-for="state in ['available','reserved','used','dismissed','expired']" :key="state">{{state}}</option></select><button>Apply</button></form><div class="list"><article v-for="item in store.promotions" :key="item.id"><div class="top"><strong>{{item.customer?.name}}</strong><span>{{item.status}}</span></div><h2>{{item.reward}}</h2><p>{{item.group}} · {{item.frequency_count}} paid visits · ₱{{item.monetary_total}}</p><button v-if="item.can_dismiss" class="outline" @click="store.dismissPromotion(item.id)">Dismiss available reward</button></article></div></section>
<section v-else-if="tab==='commissions'"><div class="metrics three"><article><strong>₱{{store.commissionSummary.pending}}</strong><span>Pending</span></article><article><strong>₱{{store.commissionSummary.paid}}</strong><span>Paid</span></article><article><strong>₱{{store.commissionSummary.net}}</strong><span>Net</span></article></div><form class="filters" @submit.prevent="store.loadCommissions(1)"><select v-model="store.commissionStaffId" aria-label="Therapist"><option :value="undefined">All therapists</option><option v-for="person in store.commissionStaff" :key="person.id" :value="person.id">{{person.name}}</option></select><select v-model="store.commissionStatus" aria-label="Commission status"><option value="">All states</option><option value="pending">Pending</option><option value="paid">Paid</option></select><button>Apply</button></form><div class="list"><article v-for="item in store.commissions" :key="item.id"><div class="top"><strong>{{item.therapist?.name}}</strong><span>{{item.status}}</span></div><h2>₱{{item.amount}}</h2><p>{{item.appointment?.service}} · {{item.appointment?.appointment_number}}</p><button v-if="item.status==='pending'&&Number(item.amount)!==0" class="outline" @click="pay(item.id)">Record payout</button></article></div></section>
<section v-else><div v-if="store.report" class="metrics"><article><strong>{{store.report.summary.appointments}}</strong><span>Appointments</span></article><article><strong>₱{{store.report.summary.revenue}}</strong><span>Paid revenue</span></article><article><strong>{{store.report.summary.customers}}</strong><span>Customers</span></article><article><strong>{{store.report.summary.feedback}}</strong><span>Feedback</span></article></div><form class="report-filters" @submit.prevent="store.loadReport(1)"><select v-model="store.reportType" aria-label="Report type"><option v-for="type in store.report?.types??['appointments','transactions','customers','promotions','feedback']" :key="type">{{type}}</option></select><input v-model="store.reportSearch" placeholder="Search report" aria-label="Search report"><input v-model="store.reportDateFrom" type="date" aria-label="From date"><input v-model="store.reportDateTo" type="date" aria-label="To date"><button>Run report</button></form><button class="primary" :disabled="store.working" @click="store.shareReport">Share CSV report</button><div v-if="store.report" class="table-shell" tabindex="0" aria-label="Report results"><table><thead><tr><th v-for="column in store.report.columns" :key="column">{{column}}</th></tr></thead><tbody><tr v-for="(row,index) in store.report.data" :key="index"><td v-for="(cell,column) in row" :key="column">{{cell??'—'}}</td></tr></tbody></table></div></section>
<section v-if="rewardOpen" class="sheet"><header><div><p class="eyebrow">REWARD RULES</p><h2>Customer reward groups</h2></div><button aria-label="Close reward settings" @click="rewardOpen=false">×</button></header><form class="editor" @submit.prevent="saveRewards"><label>Reward validity<select v-model="validity"><option :value="null">No expiry</option><option v-for="days in store.promotionValidityOptions" :key="days" :value="days">{{days}} days</option></select></label><fieldset v-for="preset in store.promotionPresets" :key="preset.key"><legend>{{preset.name}}</legend><label><input v-model="groups[preset.key].is_active" type="checkbox"> Active</label><label>Complimentary add-on<select v-model="groups[preset.key].addon_code"><option v-for="addon in store.promotionAddons" :key="addon.code" :value="addon.code">{{addon.name}}</option></select></label></fieldset><button class="primary" :disabled="store.working">Save reward settings</button></form></section></section></template>
<style scoped>
.page{width:min(100%,58rem);margin:auto;padding:max(5.2rem,calc(env(safe-area-inset-top) + 4.4rem)) 1rem calc(6rem + env(safe-area-inset-bottom))}.page h1,.page h2,.sheet h2{font-family:Georgia,serif;color:#334736}.page h1{margin:.25rem 0}.page header>p:last-child{color:#67675f}.switch{display:grid;grid-template-columns:repeat(4,1fr);gap:.25rem;padding:.25rem;margin:1rem 0;border:1px solid #dcd2c2;border-radius:.8rem;background:#fffcf7}.switch button{min-height:44px;border:0;border-radius:.6rem;background:transparent;text-transform:capitalize;font-size:.72rem;font-weight:800;color:#67675f}.switch button.active{background:#e9f2e8;color:#334736}.metrics{display:grid;grid-template-columns:1fr 1fr;gap:.5rem;margin:1rem 0}.metrics.three{grid-template-columns:repeat(3,1fr)}.metrics article{display:grid;padding:.75rem;border:1px solid #dcd2c2;border-radius:.8rem;background:#fffcf7}.metrics strong{font:700 1.1rem Georgia,serif;color:#334736}.metrics span{font-size:.66rem;color:#67675f}.filters,.report-filters{display:grid;grid-template-columns:1fr 1fr;gap:.5rem;margin:1rem 0}.filters input,.filters select,.filters button,.report-filters input,.report-filters select,.report-filters button,.editor select{min-height:48px;border:1px solid #bfb3a2;border-radius:.7rem;background:#fff;padding:.6rem;font:inherit}.filters button,.report-filters button{grid-column:1/-1;background:#4f6a4e;color:#fff;font-weight:800}.primary{min-height:48px;width:100%;border:0;border-radius:.75rem;background:#4f6a4e;color:#fff;font-weight:800}.list{display:grid;gap:.65rem}.list article{padding:1rem;border:1px solid #dcd2c2;border-radius:1rem;background:#fffcf7}.list h2{margin:.35rem 0}.list p,.list blockquote{color:#67675f}.list blockquote{margin:.5rem 0}.top{display:flex;justify-content:space-between;gap:.5rem}.top span{padding:.2rem .55rem;border-radius:999px;background:#e9f2e8;font-size:.7rem;text-transform:capitalize}.outline{min-height:44px;width:100%;border:1px solid #bfb3a2;border-radius:.65rem;background:#fff;font-weight:800}.table-shell{overflow:auto;border:1px solid #dcd2c2;border-radius:.8rem;background:#fff}table{border-collapse:collapse;min-width:48rem;width:100%}th,td{padding:.65rem;text-align:left;border-bottom:1px solid #eee5d8;font-size:.75rem}.sheet{position:fixed;z-index:35;inset:0;overflow:auto;background:#f5f0e7;padding:max(1rem,env(safe-area-inset-top)) 1rem max(1rem,env(safe-area-inset-bottom))}.sheet>header,.editor{max-width:42rem;margin:auto}.sheet>header{display:flex;justify-content:space-between}.sheet>header button{width:48px;height:48px;border:1px solid #dcd2c2;border-radius:999px;background:#fff;font-size:1.5rem}.editor{display:grid;gap:.75rem}.editor>label,.editor fieldset label{display:grid;gap:.35rem}.editor fieldset{display:grid;gap:.6rem;border:1px solid #dcd2c2;border-radius:.8rem;padding:.8rem}
</style>
